class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        vector<vector<double>> dp(n + 1, vector<double>(m, 1e9));
        dp[0][0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < m; j++) {
                dp[i][j] = min(dp[i][j], dp[i - 1][(j + 1) % m] + time[i - 1] * mul[j]);
                for (int x = 1; x <= k; x++) {
                    if (i - x >= 0) {
                        dp[i][j] = min(dp[i][j], dp[i - x][(j + 1) % m] + max(time[i - 1], time[i - x - 1]) * mul[j]);
                    }
                }
            }
        }
        return dp[n][0] == 1e9 ? -1 : dp[n][0];
    }
